    /**
     * Returns true if both the IR and Visual filename text fields are
     * currently visible on screen (we're in the add-pair form).
     */
    private boolean areIRPairFieldsVisible() {
        try {
            int found = driver.findElements(io.appium.java_client.AppiumBy.iOSNsPredicateString(
                "type == 'XCUIElementTypeTextField' AND " +
                "(value CONTAINS[c] 'photo' OR placeholderValue CONTAINS[c] 'photo' OR " +
                "label CONTAINS[c] 'Filename' OR label CONTAINS[c] 'Photo')")).size();
            return found >= 2;
        } catch (Exception e) { return false; }
    }

    /**
     * Try to reveal the Add IR Photo Pair form by tapping a button explicitly
     * labeled with "Photo Pair" or similar. STRICT match only — never falls
     * back to generic "+" / "add" / "plus" because those match too many
     * unrelated buttons (Add Photo, Add Document, Add Connection, etc.) and
     * cause us to navigate to Asset Edit or other unrelated screens.
     */
    private boolean revealAddIRPairForm() {
        try {
            WebElement btn = driver.findElement(io.appium.java_client.AppiumBy.iOSNsPredicateString(
                "type == 'XCUIElementTypeButton' AND " +
                "(label == 'Add IR Photo Pair' OR label CONTAINS[c] 'IR Photo Pair' OR " +
                "label CONTAINS[c] 'Photo Pair' OR label CONTAINS[c] 'Add Another Pair')"));
            btn.click(); sleep(600);
            return true;
        } catch (Exception ignored) { /* no Add Pair button on this screen */ }
        return false;
    }

    /**
     * Convenience: enter the SAME filename for both IR and Visual fields,
     * then tap "Add IR Photo Pair". Per user spec: names must match.
     *
     * If fields aren't visible (e.g., we tapped an existing pair and landed
     * on view mode), tries to tap "Add IR Photo Pair" / "+" to reveal the
     * form first. Dumps DOM and returns false if form still can't be found.
     */
    public boolean addIRPhotoPair(String matchingFilename) {
        // If fields aren't visible, try to reveal the form
        if (!areIRPairFieldsVisible()) {
            System.out.println("   IR/Visual fields not visible — trying to reveal Add form");
            if (revealAddIRPairForm()) {
                sleep(500);
            }
        }

        // For FLIR-IND, the Visual Photo field is disabled ("Not required for
        // FLIR-IND") — only IR is required. Skip Visual entry on failure
        // rather than aborting the whole pair-add.

        // Try entering IR Photo Filename
        if (!enterIRPhotoFilename(matchingFilename)) {
            System.out.println("⚠️ IR Photo Filename field not found. Diagnostic dump:");

            // 1. Dump StaticText labels — tells us what screen we're on
            System.out.println("   --- Visible StaticText labels (top 20) ---");
            try {
                java.util.List<WebElement> labels = driver.findElements(
                    io.appium.java_client.AppiumBy.iOSNsPredicateString(
                        "type == 'XCUIElementTypeStaticText'"));
                System.out.println("   (found " + labels.size() + " StaticText elements)");
                int dumped = 0;
                for (WebElement el : labels) {
                    try {
                        String l = el.getAttribute("label");
                        if (l != null && !l.isEmpty()) {
                            System.out.println("   [Y=" + el.getRect().getY() + "] '" + l + "'");
                            if (++dumped >= 20) break;
                        }
                    } catch (Exception eStale) { /* skip stale */ }
                }
            } catch (Exception e) {
                System.out.println("   StaticText dump FAILED: " + e.getClass().getSimpleName()
                    + ": " + (e.getMessage() != null
                        ? e.getMessage().substring(0, Math.min(120, e.getMessage().length()))
                        : ""));
            }

            // 2. Dump Button labels — finds the Add button regardless of name
            System.out.println("   --- Visible Buttons ---");
            try {
                java.util.List<WebElement> btns = driver.findElements(
                    io.appium.java_client.AppiumBy.iOSNsPredicateString(
                        "type == 'XCUIElementTypeButton'"));
                System.out.println("   (found " + btns.size() + " Buttons)");
                int dumped = 0;
                for (WebElement el : btns) {
                    try {
                        String l = el.getAttribute("label");
                        String n = el.getAttribute("name");
                        if ((l != null && !l.isEmpty()) || (n != null && !n.isEmpty())) {
                            System.out.println("   [Y=" + el.getRect().getY() + "] label='"
                                + (l == null ? "" : l) + "' name='" + (n == null ? "" : n) + "'");
                            if (++dumped >= 25) break;
                        }
                    } catch (Exception eStale) { /* skip stale */ }
                }
            } catch (Exception e) {
                System.out.println("   Button dump FAILED: " + e.getClass().getSimpleName()
                    + ": " + (e.getMessage() != null
                        ? e.getMessage().substring(0, Math.min(120, e.getMessage().length()))
                        : ""));
            }

            // 3. Dump text fields with full attributes
            System.out.println("   --- Text fields ---");
            try {
                java.util.List<WebElement> fields = driver.findElements(
                    io.appium.java_client.AppiumBy.iOSNsPredicateString(
                        "type == 'XCUIElementTypeTextField' OR " +
                        "type == 'XCUIElementTypeSecureTextField' OR " +
                        "type == 'XCUIElementTypeTextView'"));
                System.out.println("   (found " + fields.size() + " text fields)");
                for (WebElement f : fields) {
                    try {
                        System.out.println("   [Y=" + f.getRect().getY() + "] type="
                            + f.getAttribute("type") + " label='" + f.getAttribute("label")
                            + "' value='" + f.getAttribute("value")
                            + "' placeholderValue='" + f.getAttribute("placeholderValue")
                            + "' name='" + f.getAttribute("name") + "'");
                    } catch (Exception eStale) { /* skip stale */ }
                }
            } catch (Exception e) {
                System.out.println("   TextField dump FAILED: " + e.getClass().getSimpleName()
                    + ": " + (e.getMessage() != null
                        ? e.getMessage().substring(0, Math.min(120, e.getMessage().length()))
                        : ""));
            }
            return false;
        }
        // Best-effort Visual filename entry — for FLIR-IND it's "Not required"
        // and the field is disabled. Don't fail the pair add if it can't be set.
        boolean visualSet = enterVisualPhotoFilename(matchingFilename);
        System.out.println("   Visual filename set: " + visualSet
            + (visualSet ? "" : " (likely FLIR-IND where Visual is not required)"));

        // Tap the Add IR Photo Pair confirmation button
        try {
            WebElement btn = driver.findElement(io.appium.java_client.AppiumBy.iOSNsPredicateString(
                "type == 'XCUIElementTypeButton' AND " +
                "(label == 'Add IR Photo Pair' OR label CONTAINS[c] 'Add IR Photo Pair' OR " +
                "label == 'Add Pair' OR label == 'Add')"));
            btn.click(); sleep(600);
            return true;
        } catch (Exception e) { return false; }
    }

